// ═══ 1. 유닛 테스트 (Vitest/Jest) ═══

// utils/calculate.ts
export function 세금계산(소득: number): number {
    if (소득 <= 14000000) return 소득 * 0.06;
    if (소득 <= 50000000) return 소득 * 0.15 - 1260000;
    if (소득 <= 88000000) return 소득 * 0.24 - 5760000;
    return 소득 * 0.35 - 15440000;
}

