// ═══ 2. 옵저버 (이벤트 시스템) ═══

class 이벤트버스 {
    private 리스너들: Map<string, Function[]> = new Map();

    on(이벤트: string, 콜백: Function) {
        const 목록 = this.리스너들.get(이벤트) || [];
        목록.push(콜백);
        this.리스너들.set(이벤트, 목록);
    }

    emit(이벤트: string, 데이터?: any) {
        const 목록 = this.리스너들.get(이벤트) || [];
        목록.forEach(콜백 => 콜백(데이터));
    }
}

const bus = new 이벤트버스();
