interface 할인전략 {
    계산(가격: number): number;
}

const 정가: 할인전략 = { 계산: (가격) => 가격 };
const 회원할인: 할인전략 = { 계산: (가격) => 가격 * 0.9 };
const VIP할인: 할인전략 = { 계산: (가격) => 가격 * 0.8 };
const 쿠폰할인 = (금액: number): 할인전략 => ({
    계산: (가격) => Math.max(0, 가격 - 금액),
});

function 최종가격(가격: number, 전략: 할인전략): number {
    return 전략.계산(가격);
}

console.log(최종가격(10000, 회원할인));        // 9000
