데코레이터 만드는 실무 패턴입니다.

```python
import functools
import time
import logging

# ═══ 1. 기본 데코레이터 ═══
def log_call(func):
    @functools.wraps(func)  # 원본 함수 정보 보존 (필수!)
    def wrapper(*args, **kwargs):
        logging.info(f"호출: {func.__name__}")
        result = func(*args, **kwargs)
        logging.info(f"완료: {func.__name__} → {result}")
        return result
    return wrapper

@log_call
def add(a, b):
    return a + b

# ═══ 2. 인자 있는 데코레이터 ═══
def retry(max_attempts=3, delay=1.0):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            for attempt in range(1, max_attempts + 1):
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    if attempt == max_attempts:
                        raise
                    logging.warning(f"재시도 {attempt}/{max_attempts}: {e}")
                    time.sleep(delay * attempt)
        return wrapper
    return decorator

@retry(max_attempts=5, delay=0.5)
def fetch_data(url):
    return requests.get(url, timeout=5).json()

# ═══ 3. 실행 시간 측정 ═══
def timer(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        start = time.perf_counter()
        result = func(*args, **kwargs)
        elapsed = time.perf_counter() - start
        logging.info(f"{func.__name__}: {elapsed:.4f}초")
        return result
    return wrapper

@timer
def heavy_computation():
    ...

# ═══ 4. 캐시 (메모이제이션) ═══
def cache(ttl_seconds=300):
    def decorator(func):
        _cache = {}
        @functools.wraps(func)
        def wrapper(*args):
            now = time.time()
            if args in _cache:
                result, cached_at = _cache[args]
                if now - cached_at < ttl_seconds:
                    return result
            result = func(*args)
            _cache[args] = (result, now)
            return result
        return wrapper
    return decorator

@cache(ttl_seconds=60)
def get_user(user_id: int):
    return db.query(f"SELECT * FROM users WHERE id={user_id}")

# ═══ 5. 권한 체크 ═══
def require_role(*roles):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            user = get_current_user()
            if user.role not in roles:
                raise PermissionError(f"권한 부족: {user.role}")
            return func(*args, **kwargs)
        return wrapper
    return decorator

@require_role("admin", "editor")
def delete_post(post_id: int):
    ...

# ═══ 6. 비동기 데코레이터 ═══
def async_timer(func):
    @functools.wraps(func)
    async def wrapper(*args, **kwargs):
        start = time.perf_counter()
        result = await func(*args, **kwargs)
        elapsed = time.perf_counter() - start
        logging.info(f"{func.__name__}: {elapsed:.4f}초")
        return result
    return wrapper

@async_timer
async def fetch_users():
    return await db.users.find_many()
```

핵심:
- `@functools.wraps(func)` **필수** (함수 이름/문서 보존)
- 인자 없으면 2중, 인자 있으면 3중 중첩
- `*args, **kwargs`로 모든 함수에 적용 가능
- 비동기 함수는 `async def wrapper` 사용

