API 호출부터 응답까지 전부 타입 안전하게 만드는 방법입니다.

```typescript
// ═══ 1. API 응답 타입 정의 ═══
// types/api.ts

interface ApiResponse<T> {
  data: T;
  message?: string;
}

interface PaginatedResponse<T> {
  data: T[];
  pagination: {
    page: number;
    limit: number;
    total: number;
    totalPages: number;
  };
}

interface ApiError {
  error: {
    code: string;
    message: string;
    details?: Record<string, string[]>;
  };
}

interface User {
  id: string;
  name: string;
  email: string;
  role: "user" | "admin";
  createdAt: string;
}

interface CreateUserInput {
  name: string;
  email: string;
  password: string;
}

// ═══ 2. 타입 안전한 fetch 래퍼 ═══
// lib/api-client.ts

class ApiClient {
  private baseUrl: string;

  constructor(baseUrl: string = "/api") {
    this.baseUrl = baseUrl;
  }

  private async request<T>(
    path: string,
    options?: RequestInit
  ): Promise<T> {
    const url = `${this.baseUrl}${path}`;

    const response = await fetch(url, {
      ...options,
      headers: {
        "Content-Type": "application/json",
        ...options?.headers,
      },
    });

    if (!response.ok) {
      const error: ApiError = await response.json();
      throw new ApiRequestError(
        error.error.message,
        response.status,
        error.error.code,
        error.error.details,
      );
    }

    return response.json();
  }

  // GET
  get<T>(path: string, params?: Record<string, string>): Promise<T> {
    const query = params ? "?" + new URLSearchParams(params).toString() : "";
    return this.request<T>(`${path}${query}`);
  }

  // POST
  post<T>(path: string, body: unknown): Promise<T> {
    return this.request<T>(path, {
      method: "POST",
      body: JSON.stringify(body),
    });
  }

  // PATCH
  patch<T>(path: string, body: unknown): Promise<T> {
    return this.request<T>(path, {
      method: "PATCH",
      body: JSON.stringify(body),
    });
  }

  // DELETE
  delete<T = void>(path: string): Promise<T> {
    return this.request<T>(path, { method: "DELETE" });
  }
}

// 커스텀 에러
class ApiRequestError extends Error {
  constructor(
    message: string,
    public status: number,
    public code: string,
    public details?: Record<string, string[]>,
  ) {
    super(message);
    this.name = "ApiRequestError";
  }
}

// 싱글톤 인스턴스
export const api = new ApiClient();

// ═══ 3. 도메인별 API 함수 ═══
// lib/api/users.ts

export const usersApi = {
  list: (params?: { page?: number; search?: string }) =>
    api.get<PaginatedResponse<User>>("/users", {
      page: String(params?.page ?? 1),
      ...(params?.search && { search: params.search }),
    }),

  getById: (id: string) =>
    api.get<ApiResponse<User>>(`/users/${id}`),

  create: (input: CreateUserInput) =>
    api.post<ApiResponse<User>>("/users", input),

  update: (id: string, input: Partial<CreateUserInput>) =>
    api.patch<ApiResponse<User>>(`/users/${id}`, input),

  delete: (id: string) =>
    api.delete(`/users/${id}`),
};

// ═══ 4. React Hook으로 사용 ═══
// hooks/use-users.ts

import { useQuery, useMutation, useQueryClient } from "@tanstack/react-query";

export function useUsers(params?: { page?: number; search?: string }) {
  return useQuery({
    queryKey: ["users", params],
    queryFn: () => usersApi.list(params),
  });
}

export function useUser(id: string) {
  return useQuery({
    queryKey: ["user", id],
    queryFn: () => usersApi.getById(id),
    enabled: !!id,
  });
}

export function useCreateUser() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: usersApi.create,
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["users"] });
    },
  });
}

// ═══ 5. 컴포넌트에서 사용 ═══
function UserList() {
  const { data, isLoading, error } = useUsers({ page: 1 });
  const createUser = useCreateUser();

  if (isLoading) return <Skeleton />;
  if (error) return <ErrorView error={error} />;

  // data는 PaginatedResponse<User> 타입!
  // data.data는 User[] 타입! → 자동완성 동작
  return (
    <ul>
      {data.data.map(user => (
        <li key={user.id}>
          {user.name} ({user.email})
        </li>
      ))}
    </ul>
  );
}
```

전체 흐름에서 **한 번도 `any`를 사용하지 않고** 완전한 타입 안전성을 확보합니다!

