  switchMap(() => from(fetch("/api/stats").then((r) => r.json()))),
  retry({ count: 3, delay: 1000 }),    // 3회 재시도
  shareReplay(1),                       // 구독자 간 결과 공유
);

// 3. 무한 스크롤
