const state$ = action$.pipe(
  scan((state: AppState, action: Action): AppState => {
    switch (action.type) {
      case "LOAD_START":
        return { ...state, loading: true, error: null };
      case "LOAD_SUCCESS":
        return { ...state, loading: false, users: action.users };
      case "LOAD_ERROR":
