app = FastAPI()

# 연결된 클라이언트 관리
class 채팅매니저:
    def __init__(self):
        self.연결들: list[WebSocket] = []

    async def 연결추가(self, ws: WebSocket):
        await ws.accept()
        self.연결들.append(ws)

    def 연결제거(self, ws: WebSocket):
        self.연결들.remove(ws)

    async def 전체전송(self, 메시지: dict):
        for 연결 in self.연결들:
            try:
                await 연결.send_json(메시지)
            except:
                pass

매니저 = 채팅매니저()

@app.websocket("/ws/{닉네임}")
async def 채팅(ws: WebSocket, 닉네임: str):
    await 매니저.연결추가(ws)

    # 입장 알림
    await 매니저.전체전송({
        "유형": "시스템",
        "내용": f"{닉네임}님이 입장했습니다.",
        "시간": datetime.now().strftime("%H:%M"),
    })

    try:
        while True:
            데이터 = await ws.receive_text()
            await 매니저.전체전송({
                "유형": "메시지",
                "닉네임": 닉네임,
                "내용": 데이터,
                "시간": datetime.now().strftime("%H:%M"),
            })
    except WebSocketDisconnect:
        매니저.연결제거(ws)
        await 매니저.전체전송({
            "유형": "시스템",
            "내용": f"{닉네임}님이 퇴장했습니다.",
            "시간": datetime.now().strftime("%H:%M"),
        })

app.mount("/", StaticFiles(directory="static", html=True))
