```typescript
// ═══ Next.js SSE API Route ═══
// app/api/chat/route.ts
export async function POST(request: Request) {
  const { messages } = await request.json();

  const encoder = new TextEncoder();
  const stream = new ReadableStream({
    async start(controller) {
      try {
        // OpenAI 스트리밍
        const response = await openai.chat.completions.create({
          model: "gpt-4o",
          messages,
          stream: true,
        });

        for await (const chunk of response) {
          const token = chunk.choices[0]?.delta?.content || "";
          if (token) {
            controller.enqueue(
              encoder.encode(`data: ${JSON.stringify({ token })}\n\n`)
            );
          }
        }

        controller.enqueue(encoder.encode(`data: [DONE]\n\n`));
      } catch (error) {
        controller.enqueue(
          encoder.encode(`data: ${JSON.stringify({ error: "서버 오류" })}\n\n`)
        );
      } finally {
        controller.close();
      }
    },
  });

  return new Response(stream, {
    headers: {
      "Content-Type": "text/event-stream",
      "Cache-Control": "no-cache",
      Connection: "keep-alive",
    },
  });
}

// ═══ 클라이언트 SSE 소비 ═══
function useStreamChat() {
  const [streaming, setStreaming] = useState(false);
  const [response, setResponse] = useState("");

  const sendMessage = async (messages: Message[]) => {
    setStreaming(true);
    setResponse("");

    const res = await fetch("/api/chat", {
      method: "POST",
      body: JSON.stringify({ messages }),
    });

    const reader = res.body!.getReader();
    const decoder = new TextDecoder();

    while (true) {
      const { done, value } = await reader.read();
      if (done) break;

      const chunk = decoder.decode(value);
      const lines = chunk.split("\n").filter((l) => l.startsWith("data: "));

      for (const line of lines) {
        const data = line.slice(6);  // "data: " 제거
        if (data === "[DONE]") break;

        try {
          const { token } = JSON.parse(data);
          setResponse((prev) => prev + token);
        } catch {}
      }
    }

    setStreaming(false);
  };

  return { sendMessage, response, streaming };
}
```

SSE 핵심:
- `text/event-stream` Content-Type
- `data: {...}

` 형식 (줄바꿈 2개 필수)
- Nginx: `X-Accel-Buffering: no` 필수
- 자동 재연결 (브라우저 기본 지원)

tRPC는 타입 안전한 API를 코드 생성 없이 만듭니다.

```typescript
// ═══ 1. 서버 설정 ═══
// server/trpc.ts
import { initTRPC, TRPCError } from "@trpc/server";
import { z } from "zod";
import superjson from "superjson";

const t = initTRPC.context<{ user: User | null }>().create({
  transformer: superjson,
});

export const router = t.router;
export const publicProcedure = t.procedure;

// 인증 미들웨어
const isAuthed = t.middleware(({ ctx, next }) => {
  if (!ctx.user) {
    throw new TRPCError({ code: "UNAUTHORIZED", message: "로그인 필요" });
  }
  return next({ ctx: { user: ctx.user } });
});

export const protectedProcedure = t.procedure.use(isAuthed);

// ═══ 2. 라우터 정의 ═══
// server/routers/user.ts
export const userRouter = router({
  // 목록 조회
  list: publicProcedure
    .input(z.object({
      page: z.number().default(1),
      limit: z.number().max(100).default(20),
      search: z.string().optional(),
    }))
    .query(async ({ input }) => {
      const { page, limit, search } = input;
      const [users, total] = await Promise.all([
        db.user.findMany({
          where: search ? { name: { contains: search } } : undefined,
          skip: (page - 1) * limit,
          take: limit,
        }),
        db.user.count(),
      ]);
      return { users, total };
    }),

  // 단일 조회
  getById: publicProcedure
    .input(z.string())
    .query(async ({ input: id }) => {
      const user = await db.user.findUnique({ where: { id } });
      if (!user) throw new TRPCError({ code: "NOT_FOUND" });
      return user;
    }),

  // 생성 (인증 필요)
  create: protectedProcedure
    .input(z.object({
      name: z.string().min(2),
      email: z.string().email(),
    }))
    .mutation(async ({ input, ctx }) => {
      return db.user.create({ data: { ...input, createdBy: ctx.user.id } });
    }),

  // 수정
  update: protectedProcedure
    .input(z.object({
      id: z.string(),
      name: z.string().min(2).optional(),
      email: z.string().email().optional(),
    }))
    .mutation(async ({ input: { id, ...data } }) => {
      return db.user.update({ where: { id }, data });
    }),

  // 삭제
  delete: protectedProcedure
    .input(z.string())
    .mutation(async ({ input: id }) => {
      await db.user.delete({ where: { id } });
    }),
});

