```typescript
// ═══ 1. 스키마 정의 ═══
// schema.graphql
type Query {
  user(id: ID!): User
  users(page: Int = 1, limit: Int = 20, search: String): UserConnection!
  post(id: ID!): Post
}

type Mutation {
  createUser(input: CreateUserInput!): User!
  updateUser(id: ID!, input: UpdateUserInput!): User!
  deleteUser(id: ID!): Boolean!
}

type Subscription {
  messageAdded(roomId: ID!): Message!
  userOnline: User!
}

type User {
  id: ID!
  name: String!
  email: String!
  role: Role!
  posts(limit: Int = 10): [Post!]!
  postCount: Int!
  createdAt: DateTime!
}

type Post {
  id: ID!
  title: String!
  content: String!
  author: User!
  comments: [Comment!]!
  tags: [String!]!
  viewCount: Int!
}

type UserConnection {
  edges: [User!]!
  totalCount: Int!
  pageInfo: PageInfo!
}

type PageInfo {
  hasNextPage: Boolean!
  hasPreviousPage: Boolean!
}

input CreateUserInput {
  name: String!
  email: String!
  role: Role = USER
}

enum Role {
  USER
  ADMIN
  EDITOR
}

// ═══ 2. 리졸버 ═══
const resolvers = {
  Query: {
    user: async (_, { id }, ctx) => {
      return ctx.db.user.findUnique({ where: { id } });
    },
    users: async (_, { page, limit, search }, ctx) => {
      const where = search
        ? { OR: [{ name: { contains: search } }, { email: { contains: search } }] }
        : {};
      const [edges, totalCount] = await Promise.all([
        ctx.db.user.findMany({ where, skip: (page - 1) * limit, take: limit }),
        ctx.db.user.count({ where }),
      ]);
      return {
        edges,
        totalCount,
        pageInfo: {
          hasNextPage: page * limit < totalCount,
          hasPreviousPage: page > 1,
        },
      };
    },
  },

  // 필드 리졸버 (N+1 방지)
  User: {
    posts: async (parent, { limit }, ctx) => {
      return ctx.loaders.postsByUser.load(parent.id);  // DataLoader
    },
    postCount: async (parent, _, ctx) => {
      return ctx.db.post.count({ where: { authorId: parent.id } });
    },
  },

  Mutation: {
    createUser: async (_, { input }, ctx) => {
      if (!ctx.user || ctx.user.role !== "ADMIN") {
        throw new AuthenticationError("관리자 권한 필요");
      }
      return ctx.db.user.create({ data: input });
    },
  },
};

// ═══ 3. DataLoader (N+1 해결) ═══
import DataLoader from "dataloader";

function createLoaders(db: PrismaClient) {
  return {
    postsByUser: new DataLoader(async (userIds: string[]) => {
      const posts = await db.post.findMany({
        where: { authorId: { in: userIds } },
      });
      // userIds 순서에 맞게 그룹핑
      return userIds.map((id) => posts.filter((p) => p.authorId === id));
    }),
  };
}
