    try {
      const res = await fetch("/api/orders", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ ...form, items }),
      });

      if (!res.ok) throw new Error("주문 실패");

      clearCart();
      router.push("/");
      alert("주문이 완료되었습니다!");
    } catch (err) {
      alert("주문 처리 중 오류가 발생했습니다");
