```javascript
const ws = new WebSocket(`ws://${location.host}`);
let myClientId = null;

ws.onopen = () => console.log("WebSocket 연결 완료");

ws.onmessage = (e) => {
  const msg = JSON.parse(e.data);

  switch (msg.type) {
    case "connected":
      myClientId = msg.clientId;
      break;
    case "poll-list":
      msg.polls.forEach((p) => renderPoll(p));
      break;
    case "new-poll":
      renderPoll(msg.poll);
      break;
    case "poll-updated":
      renderPoll(msg.poll);
      break;
    case "poll-closed":
      renderPoll(msg.poll);
      break;
  }
};

// 투표 생성 UI 토글
