      { id: "co2", name: "CO2", unit: "ppm" },
      { id: "noise", name: "소음", unit: "dB" }
    ],
    thresholds: {
      temp: { min: 18, max: 28 },
      co2: { min: 0, max: 1000 },
      noise: { min: 0, max: 70 }
    }
  });

  dm.registerDevice("WEATHER-01", {
    name: "기상 관측 센서",
    type: "weather",
    location: "옥상",
    sensors: [
      { id: "temp", name: "온도", unit: "°C" },
      { id: "pressure", name: "기압", unit: "hPa" },
      { id: "wind", name: "풍속", unit: "m/s" }
    ],
    thresholds: {
      wind: { min: 0, max: 20 }
    }
