} as const;

export type RoleName = keyof typeof DEFAULT_ROLES;

// 권한 검증 유틸
export function hasPermission(
  userPermissions: { resource: string; action: string }[],
  resource: string,
  action: string
): boolean {
  return userPermissions.some(
    (p) => p.resource === resource && p.action === action
  );
