import { NextResponse } from "next/server";

// 키 목록 조회
export async function GET() {
  const keys = await prisma.apiKey.findMany({
    orderBy: { createdAt: "desc" },
    select: {
      id: true,
      name: true,
      keyPrefix: true,
      scopes: true,
      usageCount: true,
      lastUsedAt: true,
      expiresAt: true,
      revokedAt: true,
      createdAt: true,
    },
  });

  return NextResponse.json(
    keys.map((k) => ({ ...k, scopes: JSON.parse(k.scopes) }))
  );
}

// 새 키 생성
export async function POST(request: Request) {
  const { name, scopes, expiresInDays } = await request.json();

  if (!name || !scopes?.length) {
    return NextResponse.json({ error: "이름과 권한 스코프는 필수입니다" }, { status: 400 });
  }

  const { key, hash, prefix } = generateApiKey();

  let expiresAt = null;
  if (expiresInDays) {
    expiresAt = new Date();
    expiresAt.setDate(expiresAt.getDate() + expiresInDays);
  }

  const record = await prisma.apiKey.create({
    data: {
      name,
      keyHash: hash,
      keyPrefix: prefix,
      scopes: JSON.stringify(scopes),
      expiresAt,
    },
  });

  // 주의: 평문 키는 생성 시 한 번만 보여줌
  return NextResponse.json({
    id: record.id,
    name: record.name,
    key, // 이것만 평문 반환 (이후에는 해시만 저장됨)
    prefix,
    scopes,
    expiresAt,
    message: "이 키는 다시 표시되지 않습니다. 안전하게 보관하세요.",
  }, { status: 201 });
}
