// WMO 날씨 코드 → 이모지 매핑
export default function WeatherIcon({ code, size = 48 }: { code: number; size?: number }) {
  const emoji = getEmoji(code);
  return <Text style={[styles.icon, { fontSize: size }]}>{emoji}</Text>;
}

function getEmoji(code: number): string {
  if (code === 0) return "☀️";
  if (code <= 2) return "🌤️";
  if (code === 3) return "☁️";
  if (code <= 48) return "🌫️";
  if (code <= 55) return "🌦️";
  if (code <= 65) return "🌧️";
  if (code <= 75) return "❄️";
  if (code <= 82) return "🌧️";
  return "⛈️";
}

