## src/context/ThemeContext.tsx

```typescript
import React, { createContext, useContext, useState, useMemo, ReactNode } from "react";
import { useColorScheme } from "react-native";

interface Theme {
  dark: boolean;
  colors: {
    bg: string;
    card: string;
    text: string;
    textSecondary: string;
    border: string;
    primary: string;
    tabBar: string;
  };
}

const lightTheme: Theme = {
  dark: false,
  colors: {
    bg: "#f5f5f5",
    card: "#ffffff",
    text: "#111111",
    textSecondary: "#666666",
    border: "#eeeeee",
    primary: "#1a73e8",
    tabBar: "#ffffff",
  },
};

const darkTheme: Theme = {
  dark: true,
  colors: {
    bg: "#121212",
    card: "#1e1e1e",
    text: "#e0e0e0",
    textSecondary: "#999999",
    border: "#333333",
    primary: "#8ab4f8",
    tabBar: "#1e1e1e",
  },
};

const ThemeContext = createContext<{ theme: Theme; toggleTheme: () => void }>({
  theme: lightTheme,
  toggleTheme: () => {},
});

export function ThemeProvider({ children }: { children: ReactNode }) {
  const systemScheme = useColorScheme();
  const [isDark, setIsDark] = useState(systemScheme === "dark");

  const value = useMemo(
    () => ({
      theme: isDark ? darkTheme : lightTheme,
      toggleTheme: () => setIsDark((prev) => !prev),
    }),
    [isDark]
  );

  return <ThemeContext.Provider value={value}>{children}</ThemeContext.Provider>;
}

export const useTheme = () => useContext(ThemeContext);
```

## src/store/useNewsStore.ts

```typescript
import { create } from "zustand";

export interface Article {
  id: string;
  title: string;
  summary: string;
  imageUrl: string;
  url: string;
  source: string;
  category: string;
  publishedAt: string;
  isBookmarked: boolean;
}

const CATEGORIES = ["전체", "정치", "경제", "IT", "스포츠", "문화"];

const MOCK_ARTICLES: Article[] = Array.from({ length: 30 }, (_, i) => ({
  id: `art-${i + 1}`,
  title: [
    "AI 반도체 시장, 올해 500억 달러 돌파 전망",
    "국내 스타트업 해외 투자 유치 역대 최고",
    "프로야구 개막전 관중 20만 명 돌파",
    "차세대 배터리 기술 상용화 임박",
    "문화재 디지털 복원 프로젝트 성과 발표",
    "금리 인하 기대감에 부동산 시장 활기",
  ][i % 6],
  summary: "기사의 주요 내용을 요약한 텍스트입니다. 자세한 내용은 기사를 확인하세요.",
  imageUrl: `https://picsum.photos/400/200?random=${i + 100}`,
  url: `https://example.com/article/${i + 1}`,
  source: ["한국일보", "경제신문", "IT뉴스", "스포츠투데이", "문화일보"][i % 5],
  category: CATEGORIES[1 + (i % 5)],
  publishedAt: new Date(Date.now() - i * 1800000).toISOString(),
  isBookmarked: false,
}));

interface NewsState {
  articles: Article[];
  activeCategory: string;
  categories: string[];
  isRefreshing: boolean;
  setCategory: (cat: string) => void;
  toggleBookmark: (id: string) => void;
  refreshArticles: () => Promise<void>;
  filteredArticles: () => Article[];
  bookmarkedArticles: () => Article[];
}

export const useNewsStore = create<NewsState>((set, get) => ({
  articles: MOCK_ARTICLES,
  activeCategory: "전체",
  categories: CATEGORIES,
  isRefreshing: false,

  setCategory: (cat) => set({ activeCategory: cat }),

  toggleBookmark: (id) =>
    set((state) => ({
      articles: state.articles.map((a) =>
        a.id === id ? { ...a, isBookmarked: !a.isBookmarked } : a
      ),
    })),

  refreshArticles: async () => {
    set({ isRefreshing: true });
    await new Promise((r) => setTimeout(r, 1000));
    set({ isRefreshing: false });
  },

  filteredArticles: () => {
    const { articles, activeCategory } = get();
    return activeCategory === "전체" ? articles : articles.filter((a) => a.category === activeCategory);
  },

  bookmarkedArticles: () => get().articles.filter((a) => a.isBookmarked),
}));
```

